-- Operating hours (Mon-Sat 7:00-19:00, Sun 8:00-17:00)
INSERT INTO operating_hours (id, location_id, day_of_week, open_time, close_time, is_closed)
SELECT
    gen_random_uuid(),
    loc.id,
    d.dow,
    CASE WHEN d.dow = 0 THEN '08:00' ELSE '07:00' END::time,
    CASE WHEN d.dow = 0 THEN '17:00' ELSE '19:00' END::time,
    false
FROM locations loc
CROSS JOIN (SELECT generate_series(0, 6) AS dow) d;

